<body>
<div class="container">
<div class="hero">
<h1><span class="fire">&#128293;</span> Roast My Website</h1>
<p class="subtitle">The AI Website Roaster</p>
<p class="desc">Enter any URL and our AI will brutally (but lovingly) roast your website's design, UX, and everything in between. Free. Instant. Hilarious.</p>
</div>

<div class="input-section">
<h2>&#127919; Drop a URL, Get Roasted</h2>
<p class="hint">We'll analyze the site and deliver a professional-grade roast</p>
<div class="url-form">
<input type="url" class="url-input" id="urlInput" placeholder="https://example.com" autocomplete="url">
<button class="roast-btn" id="roastBtn" onclick="roastWebsite()"><span class="fire-emoji">&#128293;</span> Roast It!</button>
</div>
</div>

<div class="examples">
<p>Try these examples:</p>
<div class="example-btns">
<button class="example-btn" onclick="setUrl('https://www.craigslist.org')">Craigslist</button>
<button class="example-btn" onclick="setUrl('https://www.arngren.net')">Arngren</button>
<button class="example-btn" onclick="setUrl('https://www.wikipedia.org')">Wikipedia</button>
<button class="example-btn" onclick="setUrl('https://www.amazon.com')">Amazon</button>
<button class="example-btn" onclick="setUrl('https://www.reddit.com')">Reddit</button>
</div>
</div>

<div class="loading" id="loading">
<div class="spinner"></div>
<p>&#128293; Roasting in progress...</p>
<p class="loading-msgs" id="loadingMsg">Inspecting the crime scene...</p>
</div>

<div class="result-section" id="resultSection">
<div class="result-card">
<div class="score-section">
<div class="score-label">&#9878; Design Crime Score</div>
<div class="score-value" id="scoreValue">?</div>
<div class="score-subtitle" id="scoreSubtitle">out of 10</div>
</div>
<div class="roast-url" id="roastUrl"></div>
<div class="roast-content" id="roastContent"></div>
</div>
</div>

<div class="share-section" id="shareSection">
<h3>&#128227; Share the Roast!</h3>
<div class="share-btns">
<a class="share-btn share-twitter" id="shareTwitter" href="#" target="_blank">&#120143; Share on X</a>
<a class="share-btn share-reddit" id="shareReddit" href="#" target="_blank">&#129429; Post on Reddit</a>
<button class="share-btn share-copy" onclick="copyRoast()">&#128203; Copy Roast</button>
</div>
</div>

<div class="promo-banner">
<h3>&#11088; Love Our AI Tools?</h3>
<p>Get premium n8n workflow templates, prompt engineering guides, and more!</p>
<a href="https://payhip.com/ArmanisDevTools" target="_blank">&#128722; Visit Our Store</a>
</div>

<div class="more-tools">
<h3>&#128295; More Free AI Tools</h3>
<p>Check out our other free tools:</p>
<div class="tool-links">
<a href="https://crazeemedia.app.n8n.cloud/webhook/roast-my-code" class="tool-link">&#128293; Roast My Code</a>
<a href="https://crazeemedia.app.n8n.cloud/webhook/email-writer" class="tool-link">&#9993; AI Email Writer</a>
<a href="https://crazeemedia.app.n8n.cloud/webhook/linkedin-writer" class="tool-link">&#128101; LinkedIn Post Gen</a>
<a href="https://crazeemedia.app.n8n.cloud/webhook/code-review" class="tool-link">&#128269; Code Reviewer</a>
<a href="https://crazeemedia.app.n8n.cloud/webhook/ai-tools" class="tool-link">&#127968; All Tools</a>
</div>
</div>

<div class="support">
<a href="https://ko-fi.com/armanidev" target="_blank">&#9829; Support on Ko-fi</a>
</div>

<div class="footer">
<p>Built with &#128293; by <a href="https://github.com/acunningham-ship-it" target="_blank">Armani</a> | Powered by AI</p>
<p style="margin-top:5px"><a href="https://payhip.com/ArmanisDevTools" target="_blank">Shop Templates</a> &middot; <a href="https://crazeemedia.app.n8n.cloud/webhook/ai-tools" target="_blank">All Tools</a></p>
</div>
</div>

<script>
const API_URL = 'https://crazeemedia.app.n8n.cloud/webhook/roast-website-api';
const loadingMsgs = [
  'Inspecting the crime scene...',
  'Calling the design police...',
  'Gathering evidence of CSS crimes...',
  'Consulting the UX tribunal...',
  'Preparing the verdict...',
  'Writing up the charges...',
  'Almost done roasting...'
];
let msgIndex = 0;
let msgInterval;
let lastRoastText = '';
let lastUrl = '';

function setUrl(url) {
  document.getElementById('urlInput').value = url;
  document.getElementById('urlInput').focus();
}

function extractScore(text) {
  const patterns = [
    /design\s*crime\s*score[:\s]*(\d+)/i,
    /score[:\s]*(\d+)\s*(?:\/\s*10|out\s*of\s*10)/i,
    /(\d+)\s*\/\s*10/,
    /(\d+)\s*out\s*of\s*10/i
  ];
  for (const p of patterns) {
    const m = text.match(p);
    if (m) return parseInt(m[1]);
  }
  return Math.floor(Math.random() * 4) + 5;
}

function formatRoast(text) {
  return text
    .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.*?)\*/g, '<em>$1</em>')
    .replace(/^### (.*$)/gm, '<strong style="font-size:1.15em;color:#ff9a76;display:block;margin:15px 0 5px">$1</strong>')
    .replace(/^## (.*$)/gm, '<strong style="font-size:1.25em;color:#ff6b35;display:block;margin:18px 0 8px">$1</strong>')
    .replace(/^# (.*$)/gm, '<strong style="font-size:1.4em;color:#ff6b35;display:block;margin:20px 0 10px">$1</strong>')
    .replace(/^[-*] (.*$)/gm, '<span style="display:block;padding-left:15px;margin:3px 0">&#8226; $1</span>')
    .replace(/^(\d+)\. (.*$)/gm, '<span style="display:block;padding-left:15px;margin:3px 0">$1. $2</span>');
}

async function roastWebsite() {
  let url = document.getElementById('urlInput').value.trim();
  if (!url) { alert('Please enter a URL!'); return; }
  if (!url.startsWith('http')) url = 'https://' + url;

  const btn = document.getElementById('roastBtn');
  const loading = document.getElementById('loading');
  const result = document.getElementById('resultSection');
  const share = document.getElementById('shareSection');

  btn.disabled = true;
  btn.innerHTML = '&#9203; Roasting...';
  result.style.display = 'none';
  share.style.display = 'none';
  loading.style.display = 'block';

  msgIndex = 0;
  document.getElementById('loadingMsg').textContent = loadingMsgs[0];
  msgInterval = setInterval(() => {
    msgIndex = (msgIndex + 1) % loadingMsgs.length;
    document.getElementById('loadingMsg').textContent = loadingMsgs[msgIndex];
  }, 3000);

  try {
    const resp = await fetch(API_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ url: url })
    });
    const data = await resp.json();
    const roastText = data.roast || data.output || 'The AI was too stunned to roast this site.';
    lastRoastText = roastText;
    lastUrl = url;

    const score = extractScore(roastText);
    document.getElementById('scoreValue').textContent = score;
    document.getElementById('scoreSubtitle').textContent = score >= 8 ? 'out of 10 - GUILTY!' : score >= 5 ? 'out of 10 - Needs Work' : 'out of 10 - Not Bad!';
    document.getElementById('roastUrl').textContent = '&#127760; ' + url;
    document.getElementById('roastContent').innerHTML = formatRoast(roastText);

    result.style.display = 'block';
    share.style.display = 'block';

    const tweetText = encodeURIComponent('I just got my website roasted by AI! Design Crime Score: ' + score + '/10 &#128293;\\n\\nTry it free: https://crazeemedia.app.n8n.cloud/webhook/roast-my-website');
    document.getElementById('shareTwitter').href = 'https://twitter.com/intent/tweet?text=' + tweetText;
    document.getElementById('shareReddit').href = 'https://reddit.com/submit?url=https://crazeemedia.app.n8n.cloud/webhook/roast-my-website&title=Roast%20My%20Website%20-%20AI%20that%20roasts%20your%20website%20design';

    result.scrollIntoView({ behavior: 'smooth', block: 'start' });
  } catch (err) {
    alert('Oops! Something went wrong. Try again.');
    console.error(err);
  } finally {
    clearInterval(msgInterval);
    loading.style.display = 'none';
    btn.disabled = false;
    btn.innerHTML = '<span class="fire-emoji">&#128293;</span> Roast It!';
  }
}

function copyRoast() {
  const text = 'Roast My Website - ' + lastUrl + '\\n\\n' + lastRoastText + '\\n\\nTry it: https://crazeemedia.app.n8n.cloud/webhook/roast-my-website';
  navigator.clipboard.writeText(text).then(() => {
    const btn = event.target;
    btn.textContent = '&#10003; Copied!';
    setTimeout(() => btn.innerHTML = '&#128203; Copy Roast', 2000);
  });
}

document.getElementById('urlInput').addEventListener('keydown', function(e) {
  if (e.key === 'Enter') roastWebsite();
});
</script>
</body>
</html>

